12: option java_package = "io.envoyproxy.envoy.extensions.access_loggers.stats.v3";
13: option java_outer_classname = "StatsProto";
14: option java_multiple_files = true;
15: option go_package = "github.com/envoyproxy/go-control-plane/envoy/extensions/access_loggers/stats/v3;statsv3";
16: option (udpa.annotations.file_status).package_version_status = ACTIVE;
