18: // [#protodoc-title: Stats logger]
19: // Configuration for an access logger that emits custom Envoy stats according to its
20: // configuration. The stats can have tags and values derived from
21: // :ref:`command operators <config_access_log_command_operators>`.
22: // [#extension: envoy.access_loggers.stats]
23: //
24: // .. warning::
25: //   It is easy to configure and use this extension in ways that create very
26: //   large numbers of stats in Envoy, which can cause excessive memory or CPU use
27: //   leading to a denial of service in Envoy, or can overwhelm any configured
28: //   stat sinks by sending too many unique metrics.
29: 
30: message Config {
31:   option (xds.annotations.v3.message_status).work_in_progress = true;
32: 
33:   // Defines a tag on a stat.
34:   message Tag {
35:     // The name of the tag.
36:     string name = 1 [(validate.rules).string = {min_len: 1}];
37: 
38:     // The value of the tag, using :ref:`command operators <config_access_log_command_operators>`.
39:     string value_format = 2 [(validate.rules).string = {min_len: 1}];
40:   }
41: 
42:   // Defines the name and tags of a stat.
43:   message Stat {
44:     // The name of the stat.
45:     string name = 1 [(validate.rules).string = {min_len: 1}];
46: 
47:     // The tags for the stat.
48:     repeated Tag tags = 2;
49:   }
50: 
51:   // Configuration for a histogram stat.
52:   message Histogram {
53:     // The histogram units. The units are needed for some stat sinks.
54:     enum Unit {
55:       Unspecified = 0;
56: 
57:       Bytes = 1;
58: 
59:       Microseconds = 2;
60: 
61:       Milliseconds = 3;
62: 
63:       // Values are scaled to range 0-1.0, indicating 0%-100%. Values can be outside this range,
64:       // but must be positive. Values extremely far out of this range may overflow.
65:       Percent = 4;
66:     }
67: 
68:     // The name and tags of this histogram.
69:     Stat stat = 1 [(validate.rules).message = {required: true}];
70: 
71:     // The units for this histogram.
72:     Unit unit = 2 [(validate.rules).enum = {defined_only: true}];
73: 
74:     // The format string for the value of this histogram, using :ref:`command operators <config_access_log_command_operators>`.
75:     // This must evaluate to a positive number.
76:     string value_format = 3 [(validate.rules).string = {min_len: 1 prefix: "%" suffix: "%"}];
77:   }
78: 
79:   // Configuration for a counter stat.
80:   message Counter {
81:     // The name and tags of this counter.
82:     Stat stat = 1 [(validate.rules).message = {required: true}];
83: 
84:     // The format string for the value to add to this counter, using :ref:`command operators <config_access_log_command_operators>`.
85:     // One of ``value_format`` or ``value_fixed`` must be configured.
86:     string value_format = 2
87:         [(validate.rules).string = {prefix: "%" suffix: "%" ignore_empty: true}];
88: 
89:     // A fixed value to add to this counter.
90:     // One of ``value_format`` or ``value_fixed`` must be configured.
91:     google.protobuf.UInt64Value value_fixed = 3 [(validate.rules).uint64 = {gt: 0}];
92:   }
93: 
94:   // The stat prefix for the generated stats.
95:   string stat_prefix = 1 [(validate.rules).string = {min_len: 1}];
96: 
97:   // The histograms this logger will emit.
98:   repeated Histogram histograms = 3;
99: 
100:   // The counters this logger will emit.
101:   repeated Counter counters = 4;
102: }
