30:                          const std::vector<Formatter::CommandParserPtr>& commands);
31: 
32:   ::opentelemetry::proto::common::v1::KeyValueList
33:   format(const Formatter::HttpFormatterContext& context, const StreamInfo::StreamInfo& info) const;
34: 
35: private:
36:   struct OpenTelemetryFormatMapWrapper;
37:   struct OpenTelemetryFormatListWrapper;
38:   using OpenTelemetryFormatValue =
39:       absl::variant<const std::vector<Formatter::FormatterProviderPtr>,
40:                     const OpenTelemetryFormatMapWrapper, const OpenTelemetryFormatListWrapper>;
41:   // We use std::list to keep the order of the repeated "values" field in the OpenTelemetry
42:   // KeyValueList.
43:   using OpenTelemetryFormatMap = std::list<std::pair<std::string, OpenTelemetryFormatValue>>;
44:   using OpenTelemetryFormatMapPtr = std::unique_ptr<OpenTelemetryFormatMap>;
45:   struct OpenTelemetryFormatMapWrapper {
46:     OpenTelemetryFormatMapPtr value_;
47:   };
48: 
49:   using OpenTelemetryFormatList = std::list<OpenTelemetryFormatValue>;
50:   using OpenTelemetryFormatListPtr = std::unique_ptr<OpenTelemetryFormatList>;
51:   struct OpenTelemetryFormatListWrapper {
52:     OpenTelemetryFormatListPtr value_;
53:   };
54: 
55:   using OpenTelemetryFormatMapVisitor = OpenTelemetryFormatMapVisitorHelper<
56:       const std::function<::opentelemetry::proto::common::v1::AnyValue(
57:           const std::vector<Formatter::FormatterProviderPtr>&)>,
58:       const std::function<::opentelemetry::proto::common::v1::AnyValue(
59:           const OpenTelemetryFormatter::OpenTelemetryFormatMapWrapper&)>,
