74: 
75:   private:
76:     const std::vector<Formatter::CommandParserPtr>& commands_;
77:   };
78: 
79:   // Methods for doing the actual formatting.
80:   ::opentelemetry::proto::common::v1::AnyValue
81:   providersCallback(const std::vector<Formatter::FormatterProviderPtr>& providers,
82:                     const Formatter::HttpFormatterContext& context,
83:                     const StreamInfo::StreamInfo& info) const;
84:   ::opentelemetry::proto::common::v1::AnyValue openTelemetryFormatMapCallback(
85:       const OpenTelemetryFormatter::OpenTelemetryFormatMapWrapper& format_map,
86:       const OpenTelemetryFormatMapVisitor& visitor) const;
87:   ::opentelemetry::proto::common::v1::AnyValue openTelemetryFormatListCallback(
88:       const OpenTelemetryFormatter::OpenTelemetryFormatListWrapper& format_list,
89:       const OpenTelemetryFormatMapVisitor& visitor) const;
90: 
91:   const OpenTelemetryFormatMapWrapper kv_list_output_format_;
92: };
